        let mut service = Service::new();
        service.advance_stage("task-1", "initialization", "policy_check", "Beginning policy check");
        service.advance_stage("task-1", "policy_check", "provider_selection", "Policy passed");

        let history = service.get_transition_history("task-1");
        assert_eq!(history.len(), 2);
        assert_eq!(history[0].to_state, "policy_check");
        assert_eq!(history[1].to_state, "provider_selection");
    }

