            constraints: vec!["Safe".to_string()],
        };

        let coherence = service.assess_plan_coherence(&goal);
        assert!(coherence >= 0.9);
    }

    #[test]
    fn test_adaptive_planning() {
        let mut service = Service::new();
        let mut task_state = TaskStateObject {
            task_id: "task-1".to_string(),
            initial_task: "Test".to_string(),
            current_stage: "policy_check".to_string(),
            goal_contract: GoalContract {
                objective: "Test".to_string(),
                success_criteria: vec![],
                constraints: vec![],
            },
            plan_skeleton: PlanSkeleton {
                stages: vec!["stage1".to_string(), "stage2".to_string(), "stage3".to_string()],
                current_stage_index: 0,
            },
            replanning_count: 0,
            adaptive_notes: String::new(),
        };

        let result = service.generate_adaptive_plan(&mut task_state, "Need to replan");
        assert!(result);
        assert_eq!(task_state.replanning_count, 1);
        assert_eq!(task_state.plan_skeleton.current_stage_index, 1);
    }

    #[test]
    fn test_max_replanning_limit() {
        let mut service = Service::new();
        let mut task_state = TaskStateObject {
            task_id: "task-1".to_string(),
            initial_task: "Test".to_string(),
            current_stage: "execution".to_string(),
            goal_contract: GoalContract {
                objective: "Test".to_string(),
