    fn test_constraint_checking() {
        let mut service = Service::new();
        service.update_variable("mode", Value::String("test".to_string()));
        assert!(service.check_constraint("mode=\"test\""));
        assert!(!service.check_constraint("mode=\"prod\""));
    }
}

